import { checkpoint, restore } from "@tigrisdata/agent-kit";
import {
  DeleteBucketCommand,
  DeleteObjectsCommand,
  ListObjectsV2Command,
  PutObjectCommand,
  S3Client,
} from "@aws-sdk/client-s3";
import { readFile, writeFile } from "node:fs/promises";

const endpoint = "REDACTED";

const accessKeyId = process.env.TIGRIS_STORAGE_ACCESS_KEY_ID;
const secretAccessKey = process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY;

if (!accessKeyId || !secretAccessKey) {
  throw new Error("Missing TIGRIS_STORAGE_ACCESS_KEY_ID or TIGRIS_STORAGE_SECRET_ACCESS_KEY");
}

const s3 = new S3Client({
  endpoint,
  region: "REDACTED",
  credentials: { accessKeyId, secretAccessKey },
});

const normalizeBucketName = (name: string) =>
  name.toLowerCase().replace(/[^a-z0-9.-]/g, "-");

const putVersion = async (bucket: string, version: string) => {
  await s3.send(
    new PutObjectCommand({
      Bucket: bucket,
      Key: "v1.txt",
      Body: version,
      ContentType: "text/plain; charset=utf-8",
    })
  );
};

const deleteBucketContents = async (bucket: string) => {
  let continuationToken: string | undefined;

  do {
    const listResponse = await s3.send(
      new ListObjectsV2Command({
        Bucket: bucket,
        ContinuationToken: continuationToken,
      })
    );

    const objects = (listResponse.Contents ?? [])
      .map((object) => object.Key)
      .filter((key): key is string => Boolean(key))
      .map((key) => ({ Key: key }));

    if (objects.length > 0) {
      await s3.send(
        new DeleteObjectsCommand({
          Bucket: bucket,
          Delete: { Objects: objects, Quiet: true },
        })
      );
    }

    continuationToken = listResponse.NextContinuationToken;
  } while (continuationToken);
};

const deleteBucket = async (bucket: string) => {
  await deleteBucketContents(bucket);
  await s3.send(new DeleteBucketCommand({ Bucket: bucket }));
};

const main = async () => {
  const trialId = (await readFile("/logs/artifacts/trial_id", "utf8")).trim();
  if (!trialId) {
    throw new Error("Trial id file is empty");
  }

  const bucketName = normalizeBucketName(`harbor-awscli-${trialId}`);

  await putVersion(bucketName, "version=1");

  const { data: ckpt, error: ckptError } = await checkpoint(bucketName, {
    name: "before-mutation",
  });

  if (ckptError || !ckpt?.snapshotId) {
    throw new Error(`Checkpoint failed: ${ckptError?.message ?? "Unknown error"}`);
  }

  await putVersion(bucketName, "version=2");

  const { data: restored, error: restoreError } = await restore(
    bucketName,
    ckpt.snapshotId,
    {
      forkName: "rollback-recovery",
    }
  );

  if (restoreError || !restored?.bucket) {
    throw new Error(`Restore failed: ${restoreError?.message ?? "Unknown error"}`);
  }

  await writeFile(
    "/home/user/chained-ckpt/recovery.json",
    JSON.stringify({ recoveryBucket: restored.bucket })
  );

  await deleteBucket(restored.bucket);
};

await main();

