  name: "before-mutation",
});

let snapshotId = ckpt?.snapshotId;

if (!snapshotId) {
  const { data: existing, error: listError } = await listCheckpoints(
    bucketName
  );

  if (listError) {
    throw new Error(
      `Checkpoint failed: ${ckptError?.message ?? listError.message}`
    );
  }

  snapshotId = existing?.checkpoints.find(
    (entry) => entry.name === "before-mutation"
  )?.snapshotId;
}

if (!snapshotId) {
  throw new Error(`Checkpoint failed: ${ckptError?.message ?? "Unknown error"}`);
}

await putVersion(bucketName, "version=2");

const { data: restored, error: restoreError } = await restore(
  bucketName,
  snapshotId,
  {
    forkName: "rollback-recovery",
  }
);

